// Empêche l'édition de fichiers hors du worktree courant (PreToolUse Write|Edit)
import { readFileSync } from 'fs';
import { execSync } from 'child_process';
import { resolve } from 'path';

const input = JSON.parse(readFileSync(0, 'utf8'));
const filePath = input.tool_input?.file_path ?? '';
if (!filePath) process.exit(0);

try {
  const worktreeRoot = execSync('git rev-parse --show-toplevel', {
    encoding: 'utf8', timeout: 5_000,
  }).trim();

  const worktreeLines = execSync('git worktree list', {
    encoding: 'utf8', timeout: 5_000,
  }).trim().split('\n');

  const mainRoot = worktreeLines[0]?.split(/\s+/)[0] ?? '';

  // Only enforce guard when we're in a non-main worktree
  if (!mainRoot || worktreeRoot === mainRoot) process.exit(0);

  const absFile = resolve(filePath);
  if (!absFile.startsWith(worktreeRoot + '/')) {
    process.stdout.write(JSON.stringify({
      decision: 'block',
      reason: `Écriture hors du worktree courant (${worktreeRoot}). Vérifiez le chemin cible.`,
    }));
  }
} catch {
  // git absent ou pas dans un repo — laisser passer
}

#!/usr/bin/env node
// Bilan qualité complet à la fin d'une session : typecheck + lint + tests (Stop)
import { execSync } from 'child_process';
import { existsSync } from 'fs';
import { join } from 'path';

const projectDir = process.env.CLAUDE_PROJECT_DIR ?? process.cwd();

function run(label, cmd) {
  try {
    execSync(cmd, { cwd: projectDir, stdio: 'pipe', timeout: 60_000 });
    process.stderr.write(`[quality-check] ✓ ${label}\n`);
    return true;
  } catch (err) {
    const out = err.stdout?.toString()?.trim() ?? '';
    process.stderr.write(`[quality-check] ✗ ${label}\n${out ? out.slice(-500) + '\n' : ''}`);
    return false;
  }
}

const checks = [];
const hasPkg = existsSync(join(projectDir, 'package.json'));

if (hasPkg && existsSync(join(projectDir, 'tsconfig.json')))
  checks.push(['TypeScript', 'npx --no-install tsc --noEmit']);
if (hasPkg)
  checks.push(['ESLint', 'npx --no-install eslint --max-warnings=0 .']);
if (hasPkg)
  checks.push(['Tests', 'pnpm test --run 2>/dev/null || npx --no-install vitest run 2>/dev/null || true']);

const results = checks.map(([label, cmd]) => run(label, cmd));
const failed  = results.filter(r => !r).length;

if (failed > 0)
  process.stderr.write(`[quality-check] ${failed}/${checks.length} vérification(s) échouée(s).\n`);
else if (checks.length > 0)
  process.stderr.write(`[quality-check] ✓ Tous les contrôles qualité passent.\n`);

#!/usr/bin/env node
// Copie les fichiers .env du dépôt principal vers le worktree (WorktreeCreate)
import { execSync } from 'child_process';
import { existsSync, copyFileSync } from 'fs';
import { join } from 'path';
import { fileURLToPath } from 'url';

function defaultExec(cmd) {
  try { return execSync(cmd, { encoding: 'utf8', timeout: 10_000 }).trim(); } catch { return ''; }
}

export function run({
  exec = defaultExec,
  exists = existsSync,
  copy = copyFileSync,
} = {}) {
  const worktreeList = exec('git worktree list');
  const mainDir = worktreeList.split('\n')[0]?.split(/\s+/)[0] ?? '';
  const worktreeDir = exec('git rev-parse --show-toplevel');

  if (!mainDir || !worktreeDir || mainDir === worktreeDir) return;

  for (const envFile of ['.env', '.env.local', '.env.development.local']) {
    const src = join(mainDir, envFile);
    const dst = join(worktreeDir, envFile);
    if (exists(src) && !exists(dst)) {
      copy(src, dst);
      process.stderr.write(`Copié : ${envFile} → ${worktreeDir}\n`);
    }
  }
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
  run();
}

