#!/usr/bin/env node
// SessionStart: crée un worktree isolé si la session démarre sur main/master
import { execSync } from 'child_process';
import { existsSync } from 'fs';

function exec(cmd) {
  try { return execSync(cmd, { encoding: 'utf8', timeout: 10_000 }).trim(); } catch { return ''; }
}

const branch = exec('git branch --show-current') || exec('git rev-parse --abbrev-ref HEAD');
if (!branch || !/^(main|master)$/.test(branch)) process.exit(0);

const currentRoot = exec('git rev-parse --show-toplevel');
if (!currentRoot) process.exit(0);

const worktreeList = exec('git worktree list');
const mainRoot = worktreeList.split('\n')[0]?.split(/\s+/)[0] ?? '';
if (mainRoot !== currentRoot) process.exit(0);

const date = new Date().toISOString().slice(0, 10).replace(/-/g, '');
const projectName = currentRoot.split('/').pop() ?? 'project';
const branchName = `work/session-${date}`;
const worktreePath = `${currentRoot}/../${projectName}-work-${date}`;

const todayLine = worktreeList.split('\n').slice(1).find(l => l.includes(branchName));
if (todayLine) {
  const wtPath = todayLine.split(/\s+/)[0];
  process.stdout.write(`## Worktree session existant\n- Chemin : \`${wtPath}\`\n- Branche : \`${branchName}\`\n`);
  process.exit(0);
}

try {
  execSync(`git worktree add "${worktreePath}" -b "${branchName}"`, { encoding: 'utf8', timeout: 15_000, stdio: ['ignore','ignore','ignore'] });
} catch {
  process.stdout.write(`## ⚠️  Session démarrée sur \`main\`\n- Créez un worktree ou une branche avant de modifier des fichiers.\n`);
  process.exit(0);
}

process.stdout.write(`## Worktree isolé créé\n- Chemin : \`${worktreePath}\`\n- Branche : \`${branchName}\`\n- Travaillez dans ce worktree — évitez de modifier le dépôt principal.\n`);

#!/usr/bin/env node
// SessionStart: si on est sur main/master et qu'il y a des commits distants, lance git pull
import { execSync } from 'child_process';

function exec(cmd) {
  try { return execSync(cmd, { encoding: 'utf8', timeout: 10_000 }).trim(); } catch { return ''; }
}

const branch = exec('git branch --show-current') || exec('git rev-parse --abbrev-ref HEAD');
if (!branch || !/^(main|master)$/.test(branch)) process.exit(0);

const remote = exec('git remote');
if (!remote) process.exit(0);

exec('git fetch --quiet 2>/dev/null');

const localHash  = exec('git rev-parse HEAD');
const remoteHash = exec('git rev-parse @{u} 2>/dev/null');
if (!remoteHash || localHash === remoteHash) process.exit(0);

const behind = exec('git rev-list HEAD..@{u} --count');
const ahead  = exec('git rev-list @{u}..HEAD --count');
if (parseInt(behind, 10) === 0) process.exit(0);

if (parseInt(ahead, 10) > 0) {
  process.stdout.write(`## ⚠️  Branche \`${branch}\` diverge du remote\n- ${behind} commit(s) en retard, ${ahead} en avance.\n- Résolvez avec \`git pull --rebase\`.\n`);
  process.exit(0);
}

try {
  execSync('git pull --ff-only --quiet', { encoding: 'utf8', timeout: 30_000 });
} catch {
  process.stdout.write(`## ⚠️  \`git pull\` a échoué sur \`${branch}\` — synchronisez manuellement.\n`);
  process.exit(0);
}

process.stdout.write(`## Dépôt synchronisé\n- ${behind} commit(s) récupéré(s) sur \`${branch}\`.\n`);

#!/usr/bin/env node
// SessionStart: avertit si des stashs Git non récupérés traînent depuis plusieurs jours
import { execSync } from 'child_process';

function exec(cmd) {
  try { return execSync(cmd, { encoding: 'utf8', timeout: 5_000 }).trim(); } catch { return ''; }
}

const stashList = exec('git stash list --format="%gd|%ci|%gs"');
if (!stashList) process.exit(0);

const now = Date.now();
const DAYS = 3;
const threshold = DAYS * 24 * 60 * 60 * 1000;

const stale = stashList.split('\n')
  .map(line => {
    const [ref, date, ...msgParts] = line.split('|');
    const age = now - new Date(date).getTime();
    return { ref, date: date?.trim(), msg: msgParts.join('|').trim(), age };
  })
  .filter(s => s.age > threshold);

if (stale.length === 0) process.exit(0);

const lines = [`## ⚠️  Stashs Git oubliés (${stale.length})`, `- ${stale.length} stash(s) de plus de ${DAYS} jours :` ];
for (const s of stale.slice(0, 5)) {
  const days = Math.floor(s.age / (24 * 60 * 60 * 1000));
  lines.push(`  - \`${s.ref}\` (${days}j) — ${s.msg}`);
}
lines.push('- Utilisez `git stash pop` ou `git stash drop` pour les gérer.');
process.stdout.write(lines.join('\n') + '\n');

